import React, { useState, useEffect } from "react";
import "./EditablePriceTable.css";

export interface TableProduct {
    id: number;
    name: string;
    currentPrice: number;
}

interface EditablePriceTableProps {
    products: TableProduct[];
    onPriceUpdate: (productId: number, newPrice: number) => void;
    onDelete: (productId: number) => void;
    validationFn?: (price: number) => boolean;
}

const EditablePriceTable: React.FC<EditablePriceTableProps> = ({
                                                                   products,
                                                                   onPriceUpdate,
                                                                   onDelete,
                                                                   validationFn,
                                                               }) => {
    const [drafts, setDrafts] = useState<Record<number, string>>({});

    useEffect(() => {
        // keep only drafts for still-visible rows
        setDrafts(prev => {
            const next: Record<number, string> = {};
            products.forEach(p => {
                if (prev[p.id] !== undefined) next[p.id] = prev[p.id];
            });
            return next;
        });
    }, [products]);

    const handleChange = (id: number, value: string) => {
        setDrafts(d => ({ ...d, [id]: value }));
    };

    const handleUpdate = (id: number) => {
        const raw = drafts[id]?.trim();
        const base = products.find(p => p.id === id)!.currentPrice;
        const num = raw === "" || raw == null ? base : parseFloat(raw);
        if (isNaN(num)) {
            alert("Lütfen geçerli bir sayı girin.");
            return;
        }
        if (validationFn && !validationFn(num)) {
            alert(`"${num}" geçersiz.`);
            return;
        }
        onPriceUpdate(id, num);
        // clear this draft
        setDrafts(d => {
            const c = { ...d };
            delete c[id];
            return c;
        });
    };

    return (
        <table className="price-table">
            <thead>
            <tr>
                <th>Ürün</th>
                <th>Güncel Fiyat</th>
                <th>Yeni Fiyat</th>
                <th>Güncelle</th>
                <th>Sil</th>
            </tr>
            </thead>
            <tbody>
            {products.map(p => (
                <tr key={p.id}>
                    <td>{p.name}</td>
                    <td>${p.currentPrice.toFixed(2)}</td>
                    <td>
                        <input
                            type="number"
                            className="price-input"
                            value={drafts[p.id] ?? ""}
                            onChange={e => handleChange(p.id, e.target.value)}
                            placeholder={p.currentPrice.toFixed(2)}
                            step="0.01"
                        />
                    </td>
                    <td>
                        <button className="update-btn" onClick={() => handleUpdate(p.id)}>
                            Update
                        </button>
                    </td>
                    <td>
                        <button className="delete-btn" onClick={() => onDelete(p.id)}>
                            Delete
                        </button>
                    </td>
                </tr>
            ))}
            </tbody>
        </table>
    );
};

export default EditablePriceTable;
